const activity = $('Fetch Activity').first().json;
const streamsRaw = $('Fetch Streams').first().json;

// Strava returns array of stream objects; reconstruct as keyed object
const streamArray = Array.isArray(streamsRaw) ? streamsRaw : [streamsRaw];
const streams = {};
for (const s of streamArray) {
  const key = s.series_type || s.type;
  if (key) streams[key] = s;
}

const timeData = streams.time?.data || [];
if (timeData.length === 0) {
  return [{ json: { downsampled: null, scoutPrompt: 'No stream data. Analyze based on activity summary only.\n' + JSON.stringify({ name: activity.name, type: activity.sport_type, distance: activity.distance, moving_time: activity.moving_time }, null, 2) } }];
}

// Downsample (rolling window avg, ~500 points max)
const durationSec = timeData[timeData.length - 1] || 0;
const windowSec = Math.max(30, Math.ceil(durationSec / 500));
function avgSlice(data, start, end) {
  let sum = 0, count = 0;
  for (let i = start; i < end; i++) { if (data[i] !== undefined) { sum += data[i]; count++; } }
  return count > 0 ? Math.round((sum / count) * 100) / 100 : 0;
}

const ds = { timeSec: [], meta: { windowSec, pointCount: 0 } };
const hrData = streams.heartrate?.data;
const velData = streams.velocity_smooth?.data;
const altData = streams.altitude?.data;
const cadData = streams.cadence?.data;
const distData = streams.distance?.data;
const latlngData = streams.latlng?.data;
const gradeData = streams.grade_smooth?.data;

if (hrData) ds.heartrateBpm = [];
if (velData) ds.velocitySmooth = [];
if (altData) ds.altitudeM = [];
if (cadData) ds.cadenceRpm = [];
if (distData) ds.distanceM = [];
if (latlngData) ds.latlng = [];
if (gradeData) ds.gradeSmooth = [];

let wStart = 0;
while (wStart < timeData.length) {
  const wTime = timeData[wStart] || 0;
  let wEnd = wStart;
  while (wEnd < timeData.length && (timeData[wEnd] || 0) < wTime + windowSec) wEnd++;
  if (wEnd === wStart) wEnd++;
  ds.timeSec.push(wTime);
  if (distData && ds.distanceM) ds.distanceM.push(distData[wEnd - 1] || 0);
  if (latlngData && ds.latlng) { const p = latlngData[wEnd-1]; ds.latlng.push(p ? [p[0],p[1]] : [0,0]); }
  if (altData && ds.altitudeM) ds.altitudeM.push(avgSlice(altData, wStart, wEnd));
  if (hrData && ds.heartrateBpm) ds.heartrateBpm.push(avgSlice(hrData, wStart, wEnd));
  if (velData && ds.velocitySmooth) ds.velocitySmooth.push(avgSlice(velData, wStart, wEnd));
  if (cadData && ds.cadenceRpm) ds.cadenceRpm.push(avgSlice(cadData, wStart, wEnd));
  if (gradeData && ds.gradeSmooth) ds.gradeSmooth.push(avgSlice(gradeData, wStart, wEnd));
  wStart = wEnd;
}
ds.meta.pointCount = ds.timeSec.length;

// Compute HR drift for scout
let hrDrift = null;
if (hrData && hrData.length > 10) {
  const first20 = avgSlice(hrData, 0, Math.floor(hrData.length * 0.2));
  const last20 = avgSlice(hrData, Math.floor(hrData.length * 0.8), hrData.length);
  hrDrift = Math.round(last20 - first20);
}

// Build scout prompt
const distKm = (activity.distance / 1000).toFixed(2);
const durMin = Math.round(activity.moving_time / 60);
const ps = activity.distance > 0 ? Math.round(activity.moving_time / (activity.distance / 1000)) : 0;
const paceStr = Math.floor(ps/60) + ':' + String(ps%60).padStart(2,'0');

let sp = 'Analyze this workout and return JSON with: workoutClassification (string), keyObservations (array of 3-5 strings), analysisDirectives (array of 2-3 strings), relevantCoachingFrameworks (array of strings).\n\n';
sp += '## Activity\n';
sp += '- Name: ' + activity.name + '\n';
sp += '- Type: ' + activity.sport_type + '\n';
sp += '- Distance: ' + distKm + ' km\n';
sp += '- Duration: ' + durMin + ' min\n';
sp += '- Pace: ' + paceStr + ' /km\n';
sp += '- Elevation: ' + (activity.total_elevation_gain || 0) + ' m\n';
if (activity.average_heartrate) sp += '- Avg HR: ' + Math.round(activity.average_heartrate) + ' bpm\n';
if (activity.max_heartrate) sp += '- Max HR: ' + Math.round(activity.max_heartrate) + ' bpm\n';
if (hrDrift !== null) sp += '- HR Drift: ' + (hrDrift > 0 ? '+' : '') + hrDrift + ' bpm\n';
if (activity.average_cadence) sp += '- Cadence: ' + Math.round(activity.average_cadence) + ' rpm\n';

if (activity.splits_metric && Array.isArray(activity.splits_metric)) {
  sp += '\n## Splits\n';
  for (const s of activity.splits_metric) {
    const splitPace = s.average_speed > 0 ? Math.round(1000 / s.average_speed) : 0;
    sp += 'Km ' + s.split + ': ' + Math.floor(splitPace/60) + ':' + String(splitPace%60).padStart(2,'0') + ' /km';
    if (s.average_heartrate) sp += ' (' + Math.round(s.average_heartrate) + ' bpm)';
    sp += '\n';
  }
}

return [{ json: { downsampled: ds, scoutPrompt: sp, hrDrift } }];

// Parse scout response
const scoutResp = $json;
const scoutText = scoutResp.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let scout;
try { scout = JSON.parse(scoutText); } catch { scout = { workoutClassification: 'unknown', keyObservations: [], analysisDirectives: [] }; }

const activity = $('Fetch Activity').first().json;
const tokenData = $('Get Token').first().json;
const dsData = $('Code Downsample').first().json;

const distKm = (activity.distance / 1000).toFixed(2);
const durMin = Math.round(activity.moving_time / 60);
const ps = activity.distance > 0 ? Math.round(activity.moving_time / (activity.distance / 1000)) : 0;
const paceStr = Math.floor(ps/60) + ':' + String(ps%60).padStart(2,'0');

const systemPrompt = 'You are mAIcoach, an expert AI running and cycling coach. Analyze workout data with the insight of an experienced coach, providing specific, actionable feedback. Be encouraging but honest. Use data to support observations. Use metric units (km, min/km, bpm). Never fabricate data -- only reference numbers from the provided context.';

let prompt = 'Analyze this workout and return a JSON object with these exact fields:\n';
prompt += '- effortScore (integer 1-10)\n';
prompt += '- executiveSummary (2-3 sentences)\n';
prompt += '- positives (array of 2-4 short strings)\n';
prompt += '- improvements (array of 1-3 short strings)\n';
prompt += '- splitAnalysis (object with "trend" and "comment" strings, or null)\n';
prompt += '- nextSession (object with "type", "durationMin" number, "intensity", "description")\n';
prompt += '- voiceSummary (1-2 sentence audio-friendly summary)\n\n';

prompt += '## Pre-Analysis Scout Brief\n';
prompt += '- Classification: ' + (scout.workoutClassification || 'N/A') + '\n';
prompt += '- Observations: ' + (scout.keyObservations || []).join('; ') + '\n';
prompt += '- Focus areas: ' + (scout.analysisDirectives || []).join('; ') + '\n\n';

prompt += '## Workout Data\n';
prompt += '- Name: ' + activity.name + '\n';
prompt += '- Type: ' + activity.sport_type + '\n';
prompt += '- Distance: ' + distKm + ' km\n';
prompt += '- Duration: ' + durMin + ' min\n';
prompt += '- Avg Pace: ' + paceStr + ' /km\n';
prompt += '- Elevation: ' + (activity.total_elevation_gain || 0) + ' m\n';
if (activity.average_heartrate) prompt += '- Avg HR: ' + Math.round(activity.average_heartrate) + ' bpm\n';
if (activity.max_heartrate) prompt += '- Max HR: ' + Math.round(activity.max_heartrate) + ' bpm\n';
if (activity.average_cadence) prompt += '- Cadence: ' + Math.round(activity.average_cadence) + ' rpm\n';
if (activity.calories) prompt += '- Calories: ' + activity.calories + '\n';

if (dsData.hrDrift !== null && dsData.hrDrift !== undefined) {
  prompt += '- HR Drift: ' + (dsData.hrDrift > 0 ? '+' : '') + dsData.hrDrift + ' bpm\n';
}

if (activity.splits_metric && Array.isArray(activity.splits_metric)) {
  prompt += '\n## Splits\n';
  for (const s of activity.splits_metric) {
    const splitPace = s.average_speed > 0 ? Math.round(1000 / s.average_speed) : 0;
    prompt += 'Km ' + s.split + ': ' + Math.floor(splitPace/60) + ':' + String(splitPace%60).padStart(2,'0') + ' /km';
    if (s.average_heartrate) prompt += ' (' + Math.round(s.average_heartrate) + ' bpm)';
    prompt += '\n';
  }
}

prompt += '\n## Athlete: ' + tokenData.athleteName + '\n';

return [{ json: { analysisPrompt: prompt, systemPrompt, scout } }];

const resp = $json;
const text = resp.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let analysis;
try { analysis = JSON.parse(text); } catch { analysis = { executiveSummary: 'Analysis parsing failed', positives: [], improvements: [], effortScore: 5 }; }

analysis.model = 'gemini-2.0-flash';

const activityId = $('Upsert Activity').first().json.activityId;
const downsampled = $('Code Downsample').first().json.downsampled;
const activity = $('Fetch Activity').first().json;
const stravaActivityId = $('Webhook').first().json.body.stravaActivityId;
const athleteName = $('Get Token').first().json.athleteName;

return [{ json: { activityId, analysis, downsampled, activityName: activity.name, stravaActivityId, athleteName, executiveSummary: analysis.executiveSummary || '' } }];
